document.addEventListener("DOMContentLoaded",()=>{const e=JSON.parse(localStorage.getItem("meditation_stats")||'{"totalSessions": 0, "causes": {}}');window.logParticipation=function(n){e.totalSessions++,e.causes[n]=(e.causes[n]||0)+1,localStorage.setItem("meditation_stats",JSON.stringify(e)),console.log(`Participated in ${n}. Total: ${e.totalSessions}`),t()};function t(){const t=document.getElementById("user-total-sessions");t&&(t.textContent=e.totalSessions)}t()})